    },
    {
      id: 5,
      kategorie: 'Versicherte Leistungen - Ruecktritt',
      aspekt: 'Verspaetung oeffentliches Verkehrsmittel (mehr als 2 Stunden)',
      own_data: 'Erstattung der Hinreise-Mehrkosten bis maximal zur Hoehe der Stornokosten.',
      rag_query: `Was erstattet die ${comp.name} Seminar-Versicherung bei Verspaetung eines oeffentlichen Verkehrsmittels um mehr als zwei Stunden? Gibt es einen Verspaetungsschutz mit Betraegen fuer Anreise-Mehrkosten, Verpflegung und Unterkunft?`
    },
    {
      id: 6,
      kategorie: 'Versicherte Leistungen - Ruecktritt',
      aspekt: 'Panne oder Unfall des eigenen Kraftfahrzeugs',
      own_data: 'Nicht versichert. Nur wenn dadurch das versicherte Verkehrsmittel versaeumt wird: Erstattung der Hinreise-Mehrkosten bis maximal zur Hoehe der Stornokosten.',
      rag_query: `Was leistet die ${comp.name} Seminar-Versicherung bei Panne oder Unfall des eigenen Kraftfahrzeugs? Werden Kosten fuer nicht genutzte Leistungen, zusaetzliche Reisekosten oder ein Mietfahrzeug erstattet?`
    },
    {
      id: 7,
      kategorie: 'Versicherte Leistungen - Ruecktritt',
      aspekt: 'Umbuchung des Seminars',
      own_data: 'Erstattung der Umbuchungskosten bis maximal zur Hoehe der Stornokosten.',
      rag_query: `Sind Umbuchungsgebuehren bei der ${comp.name} Seminar-Versicherung versichert? Bis zu welcher Hoehe werden Umbuchungsgebuehren erstattet?`
    },
    {
      id: 8,
      kategorie: 'Reiseabbruch',
      aspekt: 'Abbruch des Seminars',
      own_data: 'Nicht versichert.',
      rag_query: `Was leistet die ${comp.name} Seminar-Versicherung bei Abbruch des Seminars? Werden anteilige Preise fuer nicht genutzte Leistungen und zusaetzliche Rueckreisekosten erstattet?`
    },
    {
      id: 9,
      kategorie: 'Reiseabbruch',
      aspekt: 'Verspaetete Rueckreise vom Seminar',
      own_data: 'Nicht versichert.',
      rag_query: `Hilft die ${comp.name} Seminar-Versicherung bei verspaeteter Rueckreise vom Seminar? Wird die Rueckreise organisiert oder ein Darlehen fuer Mehrkosten gewaehrt?`
    },
    {
      id: 10,
      kategorie: 'Reiseabbruch',
      aspekt: 'Verlaengerter Aufenthalt wegen stationaerer Behandlung',
      own_data: 'Nicht versichert.',
      rag_query: `Erstattet die ${comp.name} Seminar-Versicherung zusaetzliche Unterkunftskosten bei verlaengertem Aufenthalt wegen stationaerer Behandlung? Bis zu welchem Betrag?`
    },
    {
      id: 11,
      kategorie: 'Reiseabbruch',
      aspekt: 'Verlaengerter Aufenthalt wegen ambulanter Behandlung',
      own_data: 'Nicht versichert.',
      rag_query: `Erstattet die ${comp.name} Seminar-Versicherung zusaetzliche Unterkunftskosten bei verlaengertem Aufenthalt wegen ambulanter Behandlung? Bis zu welchem Betrag?`
    },
    {
      id: 12,
      kategorie: 'Reiseabbruch',
