    },
    {
      id: 14,
      kategorie: 'Versicherte Ereignisse',
      aspekt: 'Panne oder Unfall des Kraftfahrzeuges als Ruecktrittsgrund',
      own_data: 'Nicht direkt versichert. Nur indirekt wenn dadurch das versicherte Verkehrsmittel versaeumt wird.',
      rag_query: `Ist Panne oder Unfall des eigenen Kraftfahrzeugs ein versichertes Ereignis bei der ${comp.name} Seminar-Versicherung das zum Ruecktritt berechtigt?`
    },
    {
      id: 15,
      kategorie: 'Versicherte Ereignisse',
      aspekt: 'Erkrankung, Unfall oder Tod eines Hundes oder einer Katze',
      own_data: 'Versichert.',
      rag_query: `Ist die Erkrankung, der Unfall oder Tod eines Hundes oder einer Katze ein versichertes Ereignis bei der ${comp.name} Seminar-Versicherung?`
