    },
    {
      id: 18,
      kategorie: 'Weiteres',
      aspekt: 'Mitversicherung zusaetzlich gebuchter Reiseleistungen',
      own_data: 'Nicht versichert. Die Versicherungssumme sichert den Seminarpreis ab. Weitere Reiseleistungen muessen separat versichert werden.',
      rag_query: `Sind zusaetzlich gebuchte Reiseleistungen wie Anreise, Rueckreise und Unterkunft bei der ${comp.name} Seminar-Versicherung mitversichert? Welche zeitlichen Voraussetzungen gelten?`
    },
    {
      id: 19,
      kategorie: 'Weiteres',
      aspekt: 'Maximal versicherbarer Zeitraum und Seminarreihen',
      own_data: '1 Seminarreise, unabhaengig von der Seminardauer. Bei Seminarreihen muss jedes Modul separat abgeschlossen werden.',
      rag_query: `Wie lange ist der maximal versicherbare Zeitraum bei der ${comp.name} Seminar-Versicherung? Koennen Seminarreihen mit mehreren Teilveranstaltungen versichert werden? Bis zu welcher Dauer?`
    },
    {
      id: 20,
      kategorie: 'Weiteres',
      aspekt: 'Abschlussfristen',
      own_data: 'Abschluss bis 30 Tage vor Reisebeginn oder spaetestens bis zum 3. Werktag nach der Reisebuchung.',
      rag_query: `Welche Abschlussfristen gelten fuer die ${comp.name} Seminar-Versicherung? Bis wann muss der Versicherungsvertrag abgeschlossen werden?`
    }
  ];
}

// Kartesisches Produkt: Fakten × Mitbewerber
const items = [];
for (const competitor of config.competitors) {
  const facts = buildFacts(competitor);
  for (const fact of facts) {
    items.push({
      json: { ...fact, config: { ...config, currentCompetitor: competitor } }
    });
  }
}
return items;
